html: <div id="alert" class="max-w-md mx-auto p-4 mb-4 bg-orange-100 rounded-lg shadow-md" role="alert" aria-live="assertive">
	<span class="sr-only">Alert</span>
	<button type="button" class="ml-auto -mx-1.5 -my-1.5 bg-transparent text-orange-500 hover:text-orange-600 hover:no-underline inline-flex items-center"><svg class="w-4 h-4" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fill-rule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293 4.293a1 1 0 01-1.414 1.414L11.414 10l4.293-4.293a1 1 0 011.414-1.414L12.586 8l4.293-4.293a1 1 0 01-1.414-1.414L11.586 6.586 4.293 4.293z" clip-rule="evenodd"></path></svg>
		<span class="sr-only">Dismiss</span>
	</button>
	<p className="text-sm text-gray-600 dark:text-gray-400">You have been logged out.</p>
</div>
<!-- Add an event listener to the close button to dismiss the alert -->
<script>
const alert = document.getElementById('alert');
const closeButton = alert.querySelector('button');
closeButton.addEventListener('click', () => {
  alert.remove();
});
</script>
